from dataclasses import dataclass
from collections import deque

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of food‑related triples into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build a relationship map for all subjects
    relationships = {}
    for t in triples:
        if t.subject not in relationships:
            relationships[t.subject] = []
        relationships[t.subject].append((t.predicate, t.object))

    # Find the main subject (most triples or food-related dish)
    main_subject = max(relationships.keys(), key=lambda s: len(relationships[s]))

    # Build sentence parts starting with main subject
    parts = [main_subject]

    # Handle geographic relationships first (country, region, capital)
    geo_parts = []
    for pred, obj in relationships.get(main_subject, []):
        if pred == "country":
            geo_parts.append(f"from {obj}")
        elif pred == "region":
            geo_parts.append(f"from the {obj} region")

    # Check for capital info from country/region subjects
    for pred, obj in relationships.get(main_subject, []):
        if pred in ["country", "region"] and obj in relationships:
            for sub_pred, sub_obj in relationships[obj]:
                if sub_pred == "capital":
                    geo_parts.append(f"whose capital is {sub_obj}")
                    break

    # Handle isPartOf relationships
    for pred, obj in relationships.get(main_subject, []):
        if pred == "isPartOf":
            geo_parts.append(f"part of {obj}")

    if geo_parts:
        parts.append(", ".join(geo_parts))

    # Handle food-specific attributes
    food_parts = []
    for pred, obj in relationships.get(main_subject, []):
        if pred in ["country", "region", "isPartOf"]:
            continue
        if pred == "mainIngredient":
            food_parts.append(f"with {obj} as the main ingredient")
        elif pred == "ingredient":
            food_parts.append(f"containing {obj}")
        elif pred == "dishVariation":
            food_parts.append(f"with variations like {obj}")
        elif pred == "course":
            food_parts.append(f"served as a {obj}")
        elif pred in ["servingTemperature", "served"]:
            food_parts.append(f"typically served {obj}")
        elif pred == "servingSize":
            food_parts.append(f"with a serving size of {obj}")
        elif pred == "carbohydrate":
            food_parts.append(f"containing {obj} carbohydrates")
        elif pred == "fat":
            food_parts.append(f"containing {obj} fat")
        elif pred == "protein":
            food_parts.append(f"containing {obj} protein")
        elif pred == "division":
            food_parts.append(f"of the {obj} division")
        elif pred == "family":
            food_parts.append(f"in the {obj} family")
        elif pred == "order":
            food_parts.append(f"under the {obj} order")
        elif pred == "genus":
            food_parts.append(f"of the {obj} genus")
        elif pred == "class":
            food_parts.append(f"classified as a {obj}")
        elif pred == "alternativeName":
            food_parts.append(f"also known as {obj}")
        elif pred in ["creator", "creatorOfDish"]:
            food_parts.append(f"created by {obj}")
        elif pred == "year":
            food_parts.append(f"introduced in {obj}")
        elif pred == "related":
            food_parts.append(f"related to {obj}")
        elif pred == "similarDish":
            food_parts.append(f"similar to {obj}")
        elif pred == "foundationPlace":
            food_parts.append(f"founded in {obj}")
        elif pred == "leader":
            food_parts.append(f"led by {obj}")
        elif pred == "currency":
            food_parts.append(f"using {obj} as currency")
        elif pred == "demonym":
            food_parts.append(f"with {obj}")
        elif pred == "ethnicGroup":
            food_parts.append(f"home to {obj}")
        elif pred == "language":
            food_parts.append(f"where {obj} is spoken")
        elif pred == "officialLanguage":
            food_parts.append(f"with {obj} as the official language")
        elif pred == "leaderTitle":
            food_parts.append(f"with the leader title {obj}")

    if food_parts:
        parts.append(", ".join(food_parts))

    # Join with commas and add period
    result = ", ".join(parts)
    return f"{result}."

